import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Signup = () => {
  const { signup } = useAuth();
  const navigate = useNavigate();

  const [form, setForm] = useState({ name: "", email: "", password: "", confirmPassword: "" });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState("");

  const validate = () => {
    const next = {};
    if (!form.name.trim()) next.name = "Full name is required";
    if (!form.email) next.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(form.email)) next.email = "Invalid email format";
    if (!form.password) next.password = "Password is required";
    else if (form.password.length < 6) next.password = "Minimum 6 characters";
    if (form.password !== form.confirmPassword) next.confirmPassword = "Passwords do not match";
    return next;
  };

  const onChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: "" });
    setApiError("");
  };

  const onSubmit = async (e) => {
    e.preventDefault();
    const nextErrors = validate();
    if (Object.keys(nextErrors).length) {
      setErrors(nextErrors);
      return;
    }

    setLoading(true);
    try {
      await signup({ name: form.name, email: form.email, password: form.password });
      navigate("/");
    } catch (err) {
      setApiError(err.response?.data?.message || "Signup failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = (field) => ({
    borderColor: errors[field] ? "rgba(251,113,133,0.45)" : "var(--border)",
  });

  return (
    <div className="auth-shell">
      <div className="auth-side d-none d-lg-flex flex-column justify-content-between">
        <div>
          <Link to="/" className="navbar-brand d-inline-flex align-items-center gap-3 fw-bold mb-5">
            <span
              className="d-inline-flex align-items-center justify-content-center"
              style={{ width: 40, height: 40, borderRadius: 14, background: "rgba(96,165,250,0.12)", border: "1px solid rgba(96,165,250,0.18)", color: "var(--primary)", fontFamily: "var(--font-mono)" }}
            >
              CL
            </span>
            <span>CodeLearn</span>
          </Link>
          <span className="eyebrow mb-4">Start your roadmap</span>
          <h1 className="section-heading mb-3" style={{ fontSize: "clamp(2.4rem, 4vw, 3.6rem)" }}>
            Join a cleaner learning experience.
          </h1>
          <p className="section-copy mb-4">
            Create your account to enroll in guided technical courses, follow a structured path, and track every completed lesson.
          </p>
          <div className="feature-list">
            {[
              "Modern frontend, backend, and data tracks",
              "Visible progress and completion milestones",
              "Free access to start learning immediately",
            ].map((feature) => (
              <div key={feature} className="feature-item">
                <div className="feature-icon">
                  <i className="bi bi-plus-lg" />
                </div>
                <div style={{ color: "var(--text-secondary)" }}>{feature}</div>
              </div>
            ))}
          </div>
        </div>
        <div className="surface-card p-4" style={{ boxShadow: "none" }}>
          <div style={{ color: "var(--text-muted)", textTransform: "uppercase", letterSpacing: "0.12em", fontSize: "0.74rem", fontWeight: 700 }} className="mb-2">
            Included
          </div>
          <div className="fw-bold mb-1">Course access, progress tracking, and structured lesson flows.</div>
          <div style={{ color: "var(--text-secondary)" }}>Designed to feel current on both desktop and mobile screens.</div>
        </div>
      </div>

      <div className="auth-form-wrap">
        <div className="auth-card">
          <div className="mb-4">
            <div style={{ color: "var(--text-muted)", textTransform: "uppercase", letterSpacing: "0.12em", fontSize: "0.74rem", fontWeight: 700 }} className="mb-2">
              Create account
            </div>
            <h2 className="fw-bold mb-2">Set up your profile</h2>
            <p style={{ color: "var(--text-secondary)", margin: 0 }}>
              Already registered? <Link to="/login" style={{ color: "var(--primary)", fontWeight: 700 }}>Log in</Link>
            </p>
          </div>

          {apiError && (
            <div className="alert mb-4" style={{ background: "rgba(251,113,133,0.1)", border: "1px solid rgba(251,113,133,0.3)", color: "var(--danger)", borderRadius: 18 }}>
              {apiError}
            </div>
          )}

          <form onSubmit={onSubmit} noValidate>
            {[
              { label: "Full Name", name: "name", type: "text", placeholder: "John Smith" },
              { label: "Email Address", name: "email", type: "email", placeholder: "you@example.com" },
              { label: "Password", name: "password", type: "password", placeholder: "Minimum 6 characters" },
              { label: "Confirm Password", name: "confirmPassword", type: "password", placeholder: "Repeat password" },
            ].map((field) => (
              <div className="mb-3" key={field.name}>
                <label className="form-label small fw-bold" style={{ color: "var(--text-secondary)" }}>
                  {field.label}
                </label>
                <input
                  type={field.type}
                  name={field.name}
                  className="form-control"
                  placeholder={field.placeholder}
                  value={form[field.name]}
                  onChange={onChange}
                  style={inputStyle(field.name)}
                />
                {errors[field.name] && <div className="mt-2 small" style={{ color: "var(--danger)" }}>{errors[field.name]}</div>}
              </div>
            ))}

            <button type="submit" className="btn btn-primary-custom w-100 py-3 mt-2" disabled={loading}>
              {loading ? (
                <>
                  <span className="spinner-border spinner-border-sm me-2" />
                  Creating account...
                </>
              ) : (
                "Create Account"
              )}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Signup;
